PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE products (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL,
      description TEXT,
      category TEXT NOT NULL,
      type TEXT NOT NULL,
      price REAL NOT NULL,
      pack_sessions INTEGER,
      duration_min INTEGER,
      bookable BOOLEAN NOT NULL DEFAULT 0,
      active BOOLEAN NOT NULL DEFAULT 1,
      sort_order INTEGER NOT NULL DEFAULT 0,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
    , deleted INTEGER DEFAULT 0);
CREATE TABLE clients (
      id TEXT PRIMARY KEY,
      first_name TEXT NOT NULL,
      last_name TEXT,
      phone TEXT,
      email TEXT,
      is_member BOOLEAN NOT NULL DEFAULT 0,
      children_count INTEGER NOT NULL DEFAULT 0,
      notes TEXT,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
    , deleted INTEGER DEFAULT 0, active INTEGER NOT NULL DEFAULT 1, type TEXT DEFAULT 'b2c', company_name TEXT, company_ice TEXT, company_if TEXT, company_address TEXT);
CREATE TABLE appointments (
      id TEXT PRIMARY KEY,
      client_id TEXT,
      client_name TEXT NOT NULL,
      product_id TEXT,
      service_name TEXT NOT NULL,
      starts_at DATETIME NOT NULL,
      duration_min INTEGER NOT NULL DEFAULT 60,
      status TEXT NOT NULL DEFAULT 'scheduled',
      notes TEXT,
      created_by TEXT,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, google_event_id TEXT,
      FOREIGN KEY (client_id) REFERENCES clients(id),
      FOREIGN KEY (product_id) REFERENCES products(id)
    );
CREATE TABLE sales (
      id TEXT PRIMARY KEY,
      cashier_id TEXT NOT NULL,
      client_id TEXT,
      subtotal REAL NOT NULL,
      discount REAL NOT NULL DEFAULT 0,
      discount_reason TEXT,
      total REAL NOT NULL,
      payment_method TEXT NOT NULL DEFAULT 'cash',
      note TEXT,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, payment_image TEXT,
      FOREIGN KEY (client_id) REFERENCES clients(id)
    );
CREATE TABLE sale_items (
      id TEXT PRIMARY KEY,
      sale_id TEXT NOT NULL,
      product_id TEXT,
      product_name TEXT NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL DEFAULT 1,
      line_total REAL NOT NULL,
      FOREIGN KEY (sale_id) REFERENCES sales(id) ON DELETE CASCADE,
      FOREIGN KEY (product_id) REFERENCES products(id)
    );
CREATE TABLE users (
      id TEXT PRIMARY KEY,
      email TEXT UNIQUE NOT NULL,
      password TEXT NOT NULL,
      full_name TEXT,
      role TEXT NOT NULL DEFAULT 'cashier',
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
    , avatar_url TEXT);
CREATE TABLE client_packs (
      id TEXT PRIMARY KEY,
      client_id TEXT NOT NULL,
      product_id TEXT NOT NULL,
      sessions_total INTEGER NOT NULL,
      sessions_remaining INTEGER NOT NULL,
      purchased_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (client_id) REFERENCES clients(id),
      FOREIGN KEY (product_id) REFERENCES products(id)
    );
CREATE TABLE categories (id TEXT PRIMARY KEY, name TEXT NOT NULL, slug TEXT NOT NULL UNIQUE, sort_order INTEGER NOT NULL DEFAULT 0, active BOOLEAN NOT NULL DEFAULT 1, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE settings (key TEXT PRIMARY KEY, value TEXT, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX idx_sales_date ON sales(created_at);
CREATE INDEX idx_appt_date ON appointments(starts_at);
CREATE INDEX idx_prod_cat ON products(category);
CREATE INDEX idx_clients_name ON clients(last_name, first_name);
COMMIT;
